class Solution {
    public String categorizeBox(int length, int width, int height, int mass) {
        if (length >= 104 || width >= 104 || height >= 104 || length * width * height >= 1_000_000_000 || mass >= 100) {
            if (mass >= 100 && (length >= 104 || width >= 104 || height >= 104 || length * width * height >= 1_000_000_000)) {
                return "Both";
            } else if (mass >= 100) {
                return "Heavy";
            } else {
                return "Bulky";
            }
        } else {
            return "Neither";
        }
    }
}
